import * as React from 'react';
import { ThemeProvider, createTheme } from '@mui/material/styles';
import { BrowserRouter as Router, Route, Switch } from 'react-router-dom';

const theme = createTheme({
  typography: {
    fontFamily: 'Quicksand',
    fontweightlight: 400,
    fontWeightRegular: 500,
    fontWeightMedium: 600,
    fontWeightBold: 700,
  },
  palette: {
    primary: {
      main: "#ffffff"
    },
    secondary: {
      main: '#2A3766'
    }
  }
})

function App() {
  return (
    <ThemeProvider theme={theme}>
    <Router>
      <Switch>
        <Route exact path='/'>
          <NavBar />
          <HomeContent />
        </Route>
      <Route path='/login'>
          <MainLogin />
        </Route>
      <Route path='/register'>
          <Registration />
        </Route>
      </Switch>
    </Router>
  </ThemeProvider>
);
}

export default App;
